// ── Haptic feedback helper ────────────────────────────────────────────────────
function haptic(ms = 8) {
  try { if(navigator.vibrate) navigator.vibrate(ms); } catch {}
}

function calcScore(prayers, exDone, exTotal, habDone, habTotal, calHit, sleepHrs) {
  const faith = (prayers / 5) * 30;
  const train = exTotal > 0 ? (exDone / exTotal) * 25 : 0;
  const hab = habTotal > 0 ? (habDone / habTotal) * 25 : 0;
  const fuel = calHit ? 12 : 0;
  const sleep = sleepHrs >= 7 ? 8 : sleepHrs >= 6 ? 5 : 0;
  return Math.round(faith + train + hab + fuel + sleep);
}

